content:
{
  "grammar": [
    {
      "pattern": "因為 + reason + 所以 + result",
      "structure": ["因為", "reason", "所以", "result"],
      "explanation_en": "Use '因為...所以...' to give a reason and its result. This is the most common cause-effect structure in Chinese.",
      "title": "因為...所以... (Because... Therefore...)",
      "meaning": "Because of reason A, therefore result B happens.",
      "when_to_use": [
        "When explaining why something happened",
        "When justifying an opinion or decision",
        "When connecting a cause to an effect in conversation or writing"
      ],
      "when_not_to_use": [
        "Do not use for simple listing of facts without a causal link",
        "Avoid using when the reason is obvious from context (just use 所以 alone)"
      ],
      "pragmatic_notes": "In Taiwan, it's common to drop 因為 in casual speech if the reason is clear from context, but 所以 is almost always kept. For example: '我累了，所以想休息。'",
      "word_order_notes": "The reason clause always comes first, followed by the result clause. The order is fixed: 因為 + reason + 所以 + result.",
      "english_contrast": "In English, 'because' can come before or after the result (e.g., 'I stayed home because it rained' or 'Because it rained, I stayed home'). In Chinese, the reason must come first.",
      "korean_contrast": "Korean uses '~기 때문에' or '~아서/어서' for cause-effect, which also places the reason before the result, similar to Chinese. However, Korean can sometimes omit the result if implied, which is less common in Chinese.",
      "negative_examples": [
        {
          "text": "所以我想喝咖啡因為我渴。",
          "error": "The result clause (所以) should not come before the reason clause (因為). Correct order: 因為我渴，所以我想喝咖啡。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為我餓，我吃麵。",
          "error": "Missing 所以 before the result. Use 因為...所以... to clearly connect cause and effect."
        }
      ],
      "transformation_drills": [
        "Transform: '我累。我休息。' → '因為我累，所以我休息。'",
        "Transform: '天氣很熱。我們想喝冰水。' → '因為天氣很熱，所以我們想喝冰水。'"
      ],
      "production_drills": [
        "Give a reason for being late to class using 因為...所以...",
        "Explain why you like a particular food using 因為...所以..."
      ],
      "common_error_patterns": [
        "Reversing the order of reason and result",
        "Omitting 所以 in the result clause",
        "Using 因為 twice in one sentence"
      ],
      "repair_feedback": {
        "word_order": "Remember: reason first, then result. Use 因為 before the reason and 所以 before the result.",
        "politeness": "When giving reasons in polite contexts, add 不好意思 or 抱歉 before the 因為 clause.",
        "vocabulary": "Use specific reasons (e.g., 太忙, 不舒服) rather than vague ones."
      }
    },
    {
      "pattern": "例如 / 比如 + example(s)",
      "structure": ["例如/比如", "example"],
      "explanation_en": "Use 例如 or 比如 to introduce examples. 例如 is more formal and common in writing; 比如 is more casual and used in speech.",
      "title": "例如 / 比如 (For example / Such as)",
      "meaning": "Introducing one or more examples to illustrate a point.",
      "when_to_use": [
        "When giving examples to support an opinion",
        "When listing items in a category",
        "When clarifying a general statement with specific instances"
      ],
      "when_not_to_use": [
        "Do not use when the example is the main point (use 是 instead)",
        "Avoid using 例如 in very casual speech (use 比如 instead)"
      ],
      "pragmatic_notes": "In Taiwan, 比如 is much more common in daily conversation. 例如 is used in formal writing, presentations, or when speaking to a teacher. You can also use 像是 (xiàng shì) as an even more casual alternative.",
      "word_order_notes": "例如/比如 usually comes after a general statement and before the example(s). Examples can be single items or short phrases. If listing multiple examples, separate them with commas or 和.",
      "english_contrast": "In English, 'for example' can start a new sentence. In Chinese, 例如/比如 usually follows the general statement directly without a period.",
      "korean_contrast": "Korean uses '예를 들어' which functions similarly to 例如/比如 and also comes after a general statement.",
      "negative_examples": [
        {
          "text": "我喜歡水果，比如。",
          "error": "比如 needs an example after it. Correct: '我喜歡水果，比如蘋果和香蕉。'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "例如蘋果，我喜歡吃水果。",
          "error": "The example should come after the general statement, not before. Correct: '我喜歡吃水果，例如蘋果。'"
        }
      ],
      "transformation_drills": [
        "Add examples: '台灣小吃很好吃。' → '台灣小吃很好吃，比如滷肉飯和牛肉麵。'",
        "Add examples: '他喜歡運動。' → '他喜歡運動，例如跑步和游泳。'"
      ],
      "production_drills": [
        "Name three fruits you like using 比如",
        "Give examples of weekend activities using 例如"
      ],
      "common_error_patterns": [
        "Placing 例如/比如 at the beginning of a sentence without a preceding general statement",
        "Forgetting to list any example after 例如/比如",
        "Using 例如 in very casual speech when 比如 is more natural"
      ],
      "repair_feedback": {
        "word_order": "Place 例如/比如 after the general statement, then add your example(s).",
        "politeness": "In formal contexts, prefer 例如. In casual conversation with friends, use 比如.",
        "vocabulary": "Make sure your examples are specific and relevant to the general statement."
      }
    },
    {
      "pattern": "所以 + conclusion / 因此 + conclusion",
      "structure": ["所以/因此", "conclusion"],
      "explanation_en": "Use 所以 or 因此 to introduce a conclusion or result. 因此 is more formal and used in writing; 所以 is common in both speech and writing.",
      "title": "所以 / 因此 (Therefore / Thus)",
      "meaning": "Indicating a logical conclusion or result based on previous information.",
      "when_to_use": [
        "When drawing a conclusion from reasons or evidence",
        "When stating the result of a discussion or argument",
        "When summarizing an opinion after giving reasons"
      ],
      "when_not_to_use": [
        "Do not use 所以/因此 when the conclusion is not logically connected to what came before",
        "Avoid using 因此 in very casual conversation (use 所以 instead)"
      ],
      "pragmatic_notes": "In Taiwan, 所以 is used in all contexts. 因此 is more common in academic writing, reports, or formal speeches. In conversation, you can also use 所以說 (suǒyǐ shuō) for emphasis: '所以說，我們應該早點出發。'",
      "word_order_notes": "所以/因此 usually comes at the beginning of the conclusion clause, after the reasons have been stated. It can also start a new sentence in writing.",
      "english_contrast": "In English, 'therefore' is more formal than 'so'. Similarly, 因此 is more formal than 所以. In English, 'so' can also mean 'very' (e.g., 'so big'), but 所以 only means 'therefore'.",
      "korean_contrast": "Korean uses '그래서' for 'so/therefore' in casual speech, and '따라서' or '그러므로' in formal contexts, similar to the 所以/因此 distinction.",
      "negative_examples": [
        {
          "text": "我喜歡台灣，所以台灣小吃很好吃。",
          "error": "The conclusion (台灣小吃很好吃) is not a logical result of liking Taiwan. Use a different connector or rephrase."
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為下雨，所以。",
          "error": "所以 needs a conclusion after it. Correct: '因為下雨，所以我們不去公園。'"
        }
      ],
      "transformation_drills": [
        "Add a conclusion: '他每天練習中文。' → '他每天練習中文，所以他的中文很好。'",
        "Add a conclusion: '這家餐廳很貴。' → '這家餐廳很貴，因此客人比較少。'"
      ],
      "production_drills": [
        "Give a reason and then a conclusion about your study habits using 所以",
        "Explain why you chose a particular product using 因此"
      ],
      "common_error_patterns": [
        "Using 所以/因此 without a clear logical connection to the previous statement",
        "Forgetting to state the reason before using 所以/因此",
        "Overusing 所以 in formal writing when 因此 is more appropriate"
      ],
      "repair_feedback": {
        "word_order": "所以/因此 comes after the reasons and before the conclusion. Make sure the conclusion follows logically.",
        "politeness": "In formal writing or presentations, use 因此. In casual conversation, 所以 is fine.",
        "vocabulary": "Use clear and specific conclusions. Avoid vague statements like '所以很好' without explanation."
      }
    }
  ]
}
